import zlib, base64, sys, os

_PAYLOAD = ""

try:
    _src = zlib.decompress(base64.b64decode(_PAYLOAD)).decode("utf-8")
    exec(compile(_src, "<ftool>", "exec"), {
        "__name__": "__main__",
        "__file__": os.path.abspath(sys.argv[0])
    })
except Exception as _e:
    print(f"[ERROR] Khong the chay tool: {_e}")
    print(f"  Python: {sys.version}")
    print(f"  Platform: {sys.platform}")
    sys.exit(1)
